751 
752   // Avoid merging nontemporal stores since the resulting
753   // memcpy/memset would not be able to preserve the nontemporal hint.
754   // In theory we could teach how to propagate the !nontemporal metadata to
755   // memset calls. However, that change would force the backend to
756   // conservatively expand !nontemporal memset calls back to sequences of
757   // store instructions (effectively undoing the merging).
758   if (SI->getMetadata(LLVMContext::MD_nontemporal))
759     return false;
760 
